import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { sortNotesByUpdatedAt } from './sortNotesByUpdatedAt';

describe('sortNotesByUpdatedAt', () => {
  beforeEach(() => {
    // No external dependencies to mock for this pure function
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('should handle happy path with notes having valid updatedAt timestamps', () => {
    const notes = [
      { id: 1, updatedAt: '2023-01-02T10:00:00Z' },
      { id: 2, updatedAt: '2023-01-01T09:30:00Z' },
      { id: 3, updatedAt: '2023-01-03T12:15:00Z' },
    ];

    const sorted = sortNotesByUpdatedAt(notes);

    // Expect descending order (most recent first)
    expect(sorted).toEqual([
      { id: 3, updatedAt: '2023-01-03T12:15:00Z' },
      { id: 1, updatedAt: '2023-01-02T10:00:00Z' },
      { id: 2, updatedAt: '2023-01-01T09:30:00Z' },
    ]);
  });

  it('should handle edge case where notes have identical updatedAt values', () => {
    const notes = [
      { id: 'a', updatedAt: '2023-05-05T08:00:00Z' },
      { id: 'b', updatedAt: '2023-05-05T08:00:00Z' },
    ];

    const sorted = sortNotesByUpdatedAt(notes);

    // When timestamps are equal, original order should be preserved (stable sort)
    expect(sorted).toEqual([
      { id: 'a', updatedAt: '2023-05-05T08:00:00Z' },
      { id: 'b', updatedAt: '2023-05-05T08:00:00Z' },
    ]);
  });

  it('should handle null/empty inputs gracefully', () => {
    // undefined input defaults to empty array
    expect(sortNotesByUpdatedAt(undefined as any)).toEqual([]);

    // null input should also result in empty array
    expect(sortNotesByUpdatedAt(null as any)).toEqual([]);

    // empty array remains empty
    expect(sortNotesByUpdatedAt([])).toEqual([]);

    // notes with missing updatedAt property are treated as minimal dates
    const notes = [{ id: 1 }, { id: 2, updatedAt: '2023-02-02T00:00:00Z' }];
    const sorted = sortNotesByUpdatedAt(notes as any);
    expect(sorted).toEqual([
      { id: 2, updatedAt: '2023-02-02T00:00:00Z' },
      { id: 1 },
    ]);
  });
});

